{
  "name": "FinTrust India - Premium Loan Partner",
  "description": "A premium, conversion-focused landing page for a Direct Selling Agent (DSA) offering Personal and Business loans partnered with top Indian banks."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type LoanType = 'Personal' | 'Business' | 'Home' | 'LAP';

export interface Testimonial {
  id: number;
  name: string;
  location: string;
  image: string;
  rating: number;
  text: string;
  loanType: string;
}

export interface Bank {
  name: string;
  logoText: string;
}

export interface Feature {
  title: string;
  description: string;
  icon: React.ComponentType<any>;
}

import React, { useState, useEffect } from 'react';
import { Menu, X, ShieldCheck } from 'lucide-react';

const Navbar: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToForm = () => {
    const formElement = document.getElementById('lead-form');
    if (formElement) {
      formElement.scrollIntoView({ behavior: 'smooth' });
    }
    setMobileMenuOpen(false);
  };

  return (
    <nav 
      className={`fixed w-full z-50 transition-all duration-300 ${
        isScrolled ? 'bg-white/90 backdrop-blur-md shadow-md py-3' : 'bg-transparent py-5'
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          {/* Logo */}
          <div className="flex items-center space-x-2">
            <div className="bg-brand-900 p-2 rounded-lg">
              <ShieldCheck className="w-6 h-6 text-white" />
            </div>
            <span className={`text-2xl font-bold font-serif tracking-tight ${isScrolled ? 'text-brand-900' : 'text-brand-900 lg:text-white'}`}>
              FinTrust
            </span>
          </div>

          {/* Desktop Menu */}
          <div className="hidden md:flex items-center space-x-8">
            {['Services', 'Partners', 'Process', 'Reviews'].map((item) => (
              <a 
                key={item}
                href={`#${item.toLowerCase()}`}
                className={`text-sm font-medium hover:text-brand-gold transition-colors ${
                  isScrolled ? 'text-gray-700' : 'text-gray-200'
                }`}
              >
                {item}
              </a>
            ))}
            <button 
              onClick={scrollToForm}
              className="bg-brand-gold hover:bg-yellow-600 text-white px-6 py-2.5 rounded-full font-semibold text-sm shadow-lg hover:shadow-xl transition-all transform hover:-translate-y-0.5"
            >
              Check Eligibility
            </button>
          </div>

          {/* Mobile Menu Button */}
          <div className="md:hidden">
            <button 
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className={`${isScrolled ? 'text-gray-800' : 'text-white'}`}
            >
              {mobileMenuOpen ? <X size={28} /> : <Menu size={28} />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu Dropdown */}
      {mobileMenuOpen && (
        <div className="md:hidden absolute top-full left-0 w-full bg-white shadow-xl border-t border-gray-100">
          <div className="flex flex-col p-4 space-y-4">
            {['Services', 'Partners', 'Process', 'Reviews'].map((item) => (
              <a 
                key={item}
                href={`#${item.toLowerCase()}`}
                onClick={() => setMobileMenuOpen(false)}
                className="text-gray-800 font-medium py-2 border-b border-gray-100"
              >
                {item}
              </a>
            ))}
            <button 
              onClick={scrollToForm}
              className="w-full bg-brand-gold text-white py-3 rounded-lg font-bold"
            >
              Check Eligibility
            </button>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Lock, CheckCircle, ArrowRight, Smartphone } from 'lucide-react';

const LeadForm: React.FC = () => {
  const [formData, setFormData] = useState({
    name: '',
    phone: '',
    type: 'Personal Loan',
    income: '',
    pincode: ''
  });
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    // Simulate API call
    setTimeout(() => {
      setIsSubmitting(false);
      setIsSuccess(true);
    }, 1500);
  };

  if (isSuccess) {
    return (
      <div className="glass-card p-8 rounded-2xl shadow-2xl h-full flex flex-col justify-center items-center text-center animate-fade-in">
        <div className="bg-green-100 p-4 rounded-full mb-4">
          <CheckCircle className="w-12 h-12 text-green-600" />
        </div>
        <h3 className="text-2xl font-bold text-gray-800 mb-2">Request Received!</h3>
        <p className="text-gray-600 mb-6">
          Thank you, {formData.name.split(' ')[0]}. One of our senior bank relationship managers will call you shortly on {formData.phone} to discuss your best offer.
        </p>
        <button 
          onClick={() => setIsSuccess(false)}
          className="text-brand-900 font-medium underline"
        >
          Submit another request
        </button>
      </div>
    );
  }

  return (
    <div id="lead-form" className="bg-white p-6 md:p-8 rounded-2xl shadow-2xl relative overflow-hidden border border-gray-100">
      {/* Trust Header inside form */}
      <div className="mb-6">
        <h3 className="text-2xl font-bold text-gray-900 mb-1">Check Your Eligibility</h3>
        <p className="text-sm text-gray-500 flex items-center gap-1">
          <Lock size={12} className="text-green-600" /> 
          Safe, Secure & No Impact on Credit Score
        </p>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Full Name (As per PAN)</label>
          <input
            type="text"
            name="name"
            required
            className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-brand-gold focus:border-transparent outline-none transition-all"
            placeholder="e.g. Amit Sharma"
            value={formData.name}
            onChange={handleChange}
          />
        </div>

        <div>
          <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Mobile Number</label>
          <div className="relative">
            <span className="absolute left-4 top-3.5 text-gray-400 font-medium">+91</span>
            <input
              type="tel"
              name="phone"
              required
              pattern="[0-9]{10}"
              maxLength={10}
              className="w-full pl-12 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-brand-gold focus:border-transparent outline-none transition-all"
              placeholder="98765 43210"
              value={formData.phone}
              onChange={handleChange}
            />
          </div>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Loan Type</label>
            <select
              name="type"
              className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-brand-gold outline-none"
              value={formData.type}
              onChange={handleChange}
            >
              <option>Personal Loan</option>
              <option>Business Loan</option>
              <option>Home Loan</option>
              <option>Working Capital</option>
            </select>
          </div>
          <div>
            <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">Pincode</label>
            <input
              type="text"
              name="pincode"
              required
              maxLength={6}
              className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-brand-gold outline-none"
              placeholder="110001"
              value={formData.pincode}
              onChange={handleChange}
            />
          </div>
        </div>

        <div>
           <label className="block text-xs font-semibold text-gray-500 uppercase tracking-wide mb-1">
             {formData.type.includes('Business') ? 'Annual Turnover' : 'Net Monthly Salary'}
           </label>
           <div className="relative">
             <span className="absolute left-4 top-3.5 text-gray-500 font-medium">₹</span>
             <input
              type="number"
              name="income"
              required
              className="w-full pl-10 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-lg focus:ring-2 focus:ring-brand-gold outline-none"
              placeholder={formData.type.includes('Business') ? "e.g. 50,00,000" : "e.g. 45,000"}
              value={formData.income}
              onChange={handleChange}
            />
           </div>
        </div>

        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full gold-gradient text-white font-bold py-4 rounded-lg shadow-lg hover:shadow-xl transform hover:-translate-y-0.5 transition-all flex items-center justify-center gap-2 mt-4"
        >
          {isSubmitting ? (
            'Processing...'
          ) : (
            <>
              Check Eligibility Instantly <ArrowRight size={20} />
            </>
          )}
        </button>

        <div className="text-center pt-2">
          <p className="text-[10px] text-gray-400">
            By submitting this form, you authorize FinTrust & its partner banks to call/SMS you regarding your application.
          </p>
          <div className="flex items-center justify-center gap-4 mt-3">
             <div className="flex items-center gap-1 text-xs text-gray-500">
               <Lock size={10} /> 256-bit Secure
             </div>
             <div className="flex items-center gap-1 text-xs text-gray-500">
               <Smartphone size={10} /> No Spam Policy
             </div>
          </div>
        </div>
      </form>
    </div>
  );
};

export default LeadForm;

