    // Logic Gate for Step 4
    if (step === 4) {
      if (formData.hasDefaults === 'Yes') {
         setRejectionReason("We are unable to process applications with recent payment defaults.");
         setIsRejected(true);
         return;
      }
    }

    if (step < totalSteps) {
      setStep(step + 1);
    } else {
      handleSubmit();
    }
  };

  const handleBack = () => {
    if (step > 1) setStep(step - 1);
